{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a two-step approach: first defining the energy scale (relative to the band gap or vacuum) and then applying the Rydberg formula for higher principal quantum numbers.",
  "helpers": [
    {
      "label": "helper_1",
      "instructions": "Establish the physical model for the exciton system. Identify the relationship between the band gap (Eg), the observed 1s exciton peak energy (E_1s), and the exciton binding energy (E_b). Define the zero-point reference frame (e.g., the conduction band edge or the vacuum level) and establish a consistent sign convention for binding energies (e.g., whether the Rydberg energy is expressed as a positive magnitude or a negative energy value relative to the band edge). Determine the effective Rydberg constant (Ry*) based on the 1s state."
    },
    {
      "label": "helper_2",
      "instructions": "Using the effective Rydberg constant (Ry*) and the sign convention established in Subproblem 1, calculate the Rydberg energy for the n = 3 state using the hydrogenic model formula (E_n = -Ry* / n^2 or E_n = Ry* / n^2 depending on the convention). Ensure the final numerical value strictly adheres to the sign convention defined in the first step."
    }
  ],
  "synthesis_brief": "Combine the effective Rydberg constant derived in Subproblem 1 with the n=3 scaling factor in Subproblem 2, ensuring the final value matches the required sign convention (positive magnitude or negative energy relative to the band edge)."
}

